    <g font-family="sans-serif">
      <line x1="40" y1="100" x2="660" y2="100" stroke="#3f3f46" stroke-width="2"/>
      <circle cx="70" cy="100" r="6" fill="#a1a1aa"/>
      <text x="70" y="128" fill="#e4e4e7" font-size="13" text-anchor="middle">May 14</text>
      <text x="70" y="146" fill="#a1a1aa" font-size="13" text-anchor="middle">Cmtes pass texts</text>
      <circle cx="270" cy="100" r="7" fill="#38bdf8"/>
